   634→// Analyze speech transcription for communication quality
   635→function analyzeSpeechPatterns(transcription, durationSeconds) {
   636→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   637→  const wordCount = words.length;
   638→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   639→
   640→  // Filler word detection
   641→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   642→  const fillerCounts = {};
   643→  let totalFillers = 0;
   644→  const lowerTranscription = transcription.toLowerCase();
   645→
   646→  for (const filler of fillerWords) {
   647→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   648→    const matches = lowerTranscription.match(regex);
   649→    if (matches && matches.length > 0) {
   650→      fillerCounts[filler] = matches.length;
   651→      totalFillers += matches.length;
   652→    }
   653→  }
   654→
   655→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   656→
   657→  // Pace analysis
   658→  let paceAssessment = 'good';
   659→  let paceFeedback = '';
   660→  if (wpm < 100) {
   661→    paceAssessment = 'too_slow';
   662→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   663→  } else if (wpm < 120) {
   664→    paceAssessment = 'slightly_slow';
   665→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   666→  } else if (wpm <= 160) {
   667→    paceAssessment = 'good';
   668→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   669→  } else if (wpm <= 180) {
   670→    paceAssessment = 'slightly_fast';
   671→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   672→  } else {
   673→    paceAssessment = 'too_fast';
   674→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   675→  }
   676→
   677→  // Sentence structure analysis
   678→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   679→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   680→
   681→  // Communication score (1-10)
   682→  let communicationScore = 7;
   683→  // Penalize for filler words
   684→  if (fillerRate > 5) communicationScore -= 2;
   685→  else if (fillerRate > 3) communicationScore -= 1;
   686→  // Penalize for bad pace
   687→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   688→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   689→  // Reward for good sentence structure
   690→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   691→  // Penalize for very short responses
   692→  if (wordCount < 50) communicationScore -= 2;
   693→  else if (wordCount < 100) communicationScore -= 1;
   694→  // Reward for substantial responses
   695→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   696→
   697→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   698→
   699→  return {
   700→    word_count: wordCount,
   701→    duration_seconds: durationSeconds,
   702→    words_per_minute: wpm,
   703→    filler_words: fillerCounts,
   704→    total_fillers: totalFillers,
   705→    filler_rate: Math.round(fillerRate * 10) / 10,
   706→    pace: {
   707→      assessment: paceAssessment,
   708→      wpm,
   709→      feedback: paceFeedback
   710→    },
   711→    sentence_count: sentences.length,
   712→    avg_sentence_length: avgSentenceLength,
   713→    communication_score: communicationScore,
   714→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   715→  };
   716→}
   717→
   718→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   719→  const tips = [];
   720→
   721→  if (fillerRate > 3) {
   722→    const topFillers = Object.entries(fillerCounts)
   723→      .sort((a, b) => b[1] - a[1])
   724→      .slice(0, 3)
   725→      .map(([word, count]) => `"${word}" (${count}x)`);
   726→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   727→  }
   728→
   729→  if (wpm > 160) {
   730→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   731→  } else if (wpm < 110) {
   732→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   733→  }
   734→
   735→  if (wordCount < 80) {
   736→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   737→  }
   738→
   739→  if (tips.length === 0) {
   740→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   741→  }
   742→
   743→  return tips;
   744→}
