   871→  let settled;
   872→  try {
   873→    settled = await Promise.race([
   874→      Promise.allSettled(analysisPromises),
   875→      new Promise((resolve) => setTimeout(() => {
   876→        console.warn(`[video-analysis] Overall analysis timeout after ${ANALYSIS_TIMEOUT_MS}ms — returning partial results`);
   877→        // Return all-rejected so fallbacks kick in for anything not yet done
   878→        resolve(analysisPromises.map(() => ({ status: 'rejected', reason: new Error('Overall analysis timeout') })));
