   887→  // BUG FIX: Use helper function with multiple safety layers to prevent null crashes.
   888→  // Previous null checks still let through edge cases where AI returned non-null truthy values
   889→  // that were missing expected fields, causing TypeError: Cannot read properties of null.
   890→  function safeExtract(index, fallback) {
   891→    try {
   892→      const s = settled[index];
   893→      if (s && s.status === 'fulfilled' && s.value != null && typeof s.value === 'object') {
   894→        return s.value;
