   913→    body_language: { score: 5, feedback: 'Video analysis unavailable' },
   914→    professional_appearance: { score: 5, feedback: 'Video analysis unavailable' },
   915→    overall_presentation: 5, summary: 'Video analysis temporarily unavailable.', timestamped_notes: []
   916→  });
   917→  const voiceAnalysis = (audioData && settled[3]) ? safeExtract(3, null) : null;
   918→
   919→  // Log any failures for debugging
   920→  settled.forEach((s, i) => {
   921→    if (s.status === 'rejected') {
