  1068→// AI interviewer conducts a conversational interview turn
  1069→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
  1070→  // Send last 12 turns for better context on follow-ups
  1071→  const recentConvo = conversation.slice(-12);
  1072→  const convoText = recentConvo.map(turn => {
  1073→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1074→    return `CANDIDATE: ${turn.text}`;
  1075→  }).join('\n\n');
  1076→
  1077→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1078→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
  1079→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
  1080→  const nextPlannedQuestion = remainingQuestions.length > 0
  1081→    ? remainingQuestions[0].question_text
  1082→    : null;
  1083→
  1084→  // Count consecutive follow-ups on the current topic
  1085→  let consecutiveFollowUps = 0;
  1086→  for (let i = conversation.length - 1; i >= 0; i--) {
  1087→    const t = conversation[i];
  1088→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
  1089→      consecutiveFollowUps++;
  1090→    } else if (t.role === 'interviewer' && t.action === 'transition') {
  1091→      break;
  1092→    } else if (t.role === 'candidate') {
  1093→      continue; // skip candidate turns when counting
  1094→    }
  1095→  }
  1096→
  1097→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
  1098→
  1099→CONVERSATION SO FAR:
  1100→${convoText}
  1101→
  1102→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
  1103→
  1104→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
  1105→
  1106→YOUR TASK: Act like a real interviewer. After the candidate answers:
  1107→
  1108→1. **FOLLOW UP** if the answer is:
  1109→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
  1110→   - Missing specifics (no metrics, no concrete examples, no details about their role)
  1111→   - Interesting but unexplored (they mentioned something worth digging into)
  1112→   - Missing the "so what" (they described what happened but not the impact/result)
  1113→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
  1114→
  1115→2. **TRANSITION** to the next planned question when:
  1116→   - The candidate gave a thorough, specific answer with concrete examples
  1117→   - You've already asked 2-3 follow-ups and have sufficient depth
  1118→   - The candidate clearly has nothing more to add on this topic
  1119→
  1120→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
  1121→
  1122→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
  1123→
  1124→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
  1125→
  1126→  const result = await chat(prompt, {
  1127→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1128→    maxTokens: 1024,
  1129→    subscriptionId: options.subscriptionId,
  1130→    module: 'mock_interview', feature: 'interview_turn'
  1131→  });
  1132→
  1133→  const parsed = safeParseJSON(result);
  1134→  if (parsed) return parsed;
  1135→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1136→}
