  1138→// Generate session-end feedback for a mock interview
  1139→// Returns structured format matching practice interview: content + communication + presentation
  1140→async function generateSessionFeedback(conversation, targetRole, options = {}) {
  1141→  const convoText = conversation.map(turn => {
  1142→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1143→    return `CANDIDATE: ${turn.text}`;
  1144→  }).join('\n\n');
  1145→
  1146→  // Calculate basic metrics from the text
  1147→  const candidateTurns = conversation.filter(t => t.role === 'candidate');
  1148→  const allCandidateText = candidateTurns.map(t => t.text).join(' ');
  1149→  const wordCount = allCandidateText.split(/\s+/).filter(w => w).length;
  1150→  const questionCount = conversation.filter(t => t.role === 'interviewer').length;
  1151→
  1152→  // Estimate duration from timestamps
  1153→  let durationSeconds = 0;
  1154→  if (conversation.length >= 2) {
  1155→    const first = new Date(conversation[0].timestamp || Date.now());
  1156→    const last = new Date(conversation[conversation.length - 1].timestamp || Date.now());
  1157→    durationSeconds = Math.max(60, Math.round((last - first) / 1000));
  1158→  }
  1159→  const wpm = durationSeconds > 0 ? Math.round(wordCount / (durationSeconds / 60)) : 120;
  1160→
  1161→  const prompt = `You just completed a mock interview for a "${targetRole}" position. Review the full conversation and provide structured feedback in THREE sections matching our coaching format.
  1162→
  1163→FULL INTERVIEW TRANSCRIPT:
