  1186→    "specific_tips": ["Actionable tip 1", "Actionable tip 2", "Actionable tip 3"],
  1187→    "common_mistake": "The most common interview mistake they exhibited",
  1188→    "star_method_usage": { "score": 1-10, "feedback": "How well they structured answers with Situation-Task-Action-Result" },
  1189→    "technical_depth": { "score": 1-10, "feedback": "Depth of technical knowledge and specificity" }
  1190→  },
  1191→
  1192→  "communication": {
  1193→    "score": 1-10,
  1194→    "word_count": ${wordCount},
  1195→    "words_per_minute": ${wpm},
  1196→    "duration_seconds": ${durationSeconds},
  1197→    "filler_words": {"um": 0, "uh": 0, "like": 0, "you know": 0, "so": 0, "basically": 0},
  1198→    "total_fillers": 0,
  1199→    "filler_rate": 0.0,
  1200→    "pace": {
  1201→      "assessment": "good|slightly_fast|slightly_slow|too_fast|too_slow",
  1202→      "wpm": ${wpm},
