  1204→    },
  1205→    "tips": ["Speech improvement tip 1", "Tip 2"],
  1206→    "trends": "Did their communication improve/decline over the interview? More confident later? More filler words when nervous?"
  1207→  },
  1208→
  1209→  "question_scores": [
