  1252→  // BUG FIX #4: Improved fallback with conversation-based analysis instead of "Detailed feedback unavailable"
  1253→  console.warn('[session-feedback] Failed to parse LLM response, computing basic feedback from conversation');
  1254→  const avgResponseLength = candidateTurns.length > 0
  1255→    ? Math.round(allCandidateText.split(/\s+/).length / candidateTurns.length)
