  1280→// ─── TTS: Now with automatic fallback + database caching ─────
  1281→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1282→async function textToSpeech(text, options = {}) {
  1283→  const pool = require('./db');
  1284→  const crypto = require('crypto');
  1285→
  1286→  try {
  1287→    const voice = options.voice || 'nova';
  1288→    const speed = options.speed || 1.0;
  1289→
  1290→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1291→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1292→
  1293→    // Generate cache key from text + voice
  1294→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1295→
  1296→    // Check cache first — serves audio even when daily token limit is exhausted
  1297→    try {
  1298→      const cached = await pool.query(
  1299→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1300→        [cacheKey]
  1301→      );
  1302→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1303→        const buf = Buffer.from(cached.rows[0].audio_data);
  1304→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1305→        return buf;
  1306→      }
  1307→    } catch (cacheErr) {
  1308→      // Cache miss or table doesn't exist yet — continue to API
  1309→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1310→    }
  1311→
  1312→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1313→
  1314→    // Use provider service with automatic fallback
  1315→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1316→      voice,
  1317→      speed,
  1318→      subscriptionId: options.subscriptionId,
  1319→      module: 'mock_interview', feature: 'tts',
  1320→    });
  1321→
  1322→    if (!buf) {
  1323→      console.log('[tts] All providers failed, returning null for browser fallback');
  1324→      return null;
  1325→    }
  1326→
  1327→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1328→
  1329→    // Cache the audio for future use (non-blocking)
  1330→    if (buf.length > 100) {
  1331→      pool.query(
  1332→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1333→         VALUES ($1, $2, $3, $4)
  1334→         ON CONFLICT (text_hash) DO NOTHING`,
  1335→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1336→      ).then(() => {
  1337→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1338→      }).catch(err => {
  1339→        // Non-fatal — caching failure doesn't break TTS
  1340→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1341→      });
  1342→    }
  1343→
  1344→    return buf;
  1345→  } catch (err) {
  1346→    console.error('[tts] Error:', err.message || err);
  1347→    return null;
  1348→  }
  1349→}
