   557→  isCircuitOpen(providerKey, modality) {
   558→    const key = `${providerKey}:${modality}`;
   559→    const failure = this.failures[key];
   560→    if (!failure) return false;
   561→
   562→    const elapsed = Date.now() - failure.lastFailure;
   563→    if (elapsed > CIRCUIT_BREAK_MS) {
   564→      // Circuit closed — enough time passed, allow retry
   565→      delete this.failures[key];
   566→      return false;
   567→    }
   568→    return true;
   569→  }
