   632→  isRetryable(err) {
   633→    // Network/timeout errors
   634→    if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED' || err.code === 'ECONNRESET' || err.code === 'ENOTFOUND') return true;
   635→    if (err.message && (err.message.includes('timeout') || err.message.includes('ETIMEDOUT'))) return true;
   636→
   637→    // HTTP status codes
   638→    const status = err.status || err.statusCode || (err.response && err.response.status);
   639→    if (status && RETRYABLE_STATUS.has(status)) return true;
   640→
   641→    // OpenAI SDK-specific error types
   642→    if (err.type === 'insufficient_quota' || err.code === 'insufficient_quota') return true;
   643→    if (err.type === 'rate_limit_exceeded' || err.code === 'rate_limit_exceeded') return true;
   644→
   645→    // Anthropic-specific
   646→    if (err.error && err.error.type === 'overloaded_error') return true;
   647→
   648→    // Polsia proxy wraps upstream provider errors (e.g., Gemini location block) as proxy_error
   649→    if (err.code === 'proxy_error' || (err.error && err.error.code === 'proxy_error')) return true;
