   695→        if (this.isCircuitOpen(k, modality)) return `${k}: circuit open`;
   696→        return `${k}: unknown`;
   697→      });
   698→      const err = new Error(`No available providers for ${modality}. ${reasons.join(', ')}`);
   699→      // Log failed call
