   701→        module: callMeta.module || 'unknown',
   702→        feature: callMeta.feature || '',
   703→        modality,
   704→        provider: 'none',
   705→        model: '',
   706→        latencyMs: Date.now() - callStart,
   707→        success: false,
   708→        errorMessage: err.message,
   709→        fallbackChain: allChain,
