   726→        // Wrap each provider call with a timeout to prevent hanging
   727→        const result = await Promise.race([
   728→          executeFn(providerKey),
   729→          new Promise((_, reject) => setTimeout(() => {
   730→            const err = new Error(`${providerKey} timed out after ${timeoutMs}ms for ${modality}`);
   731→            err.code = 'ETIMEDOUT';
   732→            reject(err);
   733→          }, timeoutMs))
