   748→        // Log successful call with full metadata
   749→        const latencyMs = Date.now() - callStart;
   750→        aiCallLogger.logCall({
   751→          module: callMeta.module || 'unknown',
   752→          feature: callMeta.feature || '',
   753→          modality,
   754→          provider: providerKey,
   755→          model: callMeta.model || this._getModelName(providerKey) || providerKey,
   756→          promptTokens: Math.round(tokenCount * 0.6),
   757→          completionTokens: Math.round(tokenCount * 0.4),
   758→          totalTokens: tokenCount,
   759→          latencyMs,
   760→          success: true,
   761→          fallbackChain: triedProviders.length > 1 ? triedProviders : null,
   762→          userId: callMeta.userId || null,
   763→        });
