```javascript
// BUG FIX (Feb 14, 2026): Vision providers can take 30s+ per attempt × 3 providers = 90s total.
// Safari/iOS kills fetch after ~60s with "Load failed". Wrapping in 25s timeout ensures we always
// return partial results rather than timing out the entire request.
const ANALYSIS_TIMEOUT_MS = 25000;

const analysisPromises = [
  analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
  generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
  analyzeVideoPresentation(frames, options)
];

// Add voice quality analysis if we have audio
